}, 20000);

function formatDateTime(date) {
  var year = date.getFullYear();
  var month = date.getMonth() + 1;
  var day = date.getDate();
  var hour = date.getHours();
  var minute = date.getMinutes();
  var second = date.getSeconds();

  return (
    [year, month, day]
      .map((n) => {
        var m = n.toString();
        return m[1] ? m : '0' + m;
      })
      .join('-') +
    ' ' +
    [hour, minute, second]
      .map((n) => {
        var m = n.toString();
        return m[1] ? m : '0' + m;
      })
      .join(':')
  );
}
</script>
</html>`;
