    https
      .get(url, (res) => {
        let data = '';

        res.on('data', (chunk) => {
          data += chunk;
        });

        res.on('end', () => {
          try {
            const jsonData = JSON.parse(data);
            const result = {
              bk_xAxis: [],
              bk_seriesData: [],
              bk_min: 600,
              bk_max: -600,
              map_echarts_data: [],
