    /// 当前净值
    pub net_value: Option<f64>,
    /// 更新时间
    pub update_time: Option<String>,
}

impl FundInfo {
    /// 验证基金代码格式（必须是6位数字）
    pub fn validate_code(code: &str) -> bool {
        code.len() == 6 && code.chars().all(|c| c.is_ascii_digit())
    }
}

/// 基金列表
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct FundList {
    /// 列表ID（UUID v4）
    pub id: String,
    /// 列表名称（用户自定义，1-30字符，唯一）
    pub name: String,
    /// 基金代码列表（有序，列表内唯一）
    pub fund_codes: Vec<String>,
    /// 创建时间（Unix timestamp）
    pub created_at: i64,
    /// 显示位置（用于排序）
    pub position: usize,
}

impl FundList {
    /// 检查列表中是否包含指定基金
    pub fn contains_fund(&self, fund_code: &str) -> bool {
        self.fund_codes.iter().any(|code| code == fund_code)
    }

    /// 验证列表名称（1-30字符，不能全是空格）
    pub fn validate_name(name: &str) -> bool {
        let trimmed = name.trim();
        !trimmed.is_empty() && trimmed.len() <= 30
    }
}

/// 存储格式（根数据结构）
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct StorageFormat {
    /// 数据格式版本（当前为1）
    pub version: u32,
    /// 所有用户列表
    pub lists: Vec<FundList>,
    /// 首次创建时间
    pub created_at: i64,
    /// 最后修改时间
    pub last_modified: i64,
}

impl StorageFormat {
    /// 创建新的空存储格式
    pub fn new() -> Self {
        let now = chrono::Utc::now().timestamp();
        StorageFormat {
            version: 1,
            lists: Vec::new(),
            created_at: now,
            last_modified: now,
        }
    }

    /// 更新最后修改时间
    pub fn touch(&mut self) {
        self.last_modified = chrono::Utc::now().timestamp();
    }
}

impl Default for StorageFormat {
    fn default() -> Self {
        Self::new()
    }
}

/// 应用状态
#[derive(Debug)]
pub struct AppState {
    /// 存储格式数据
    pub storage: StorageFormat,
    /// 存储文件路径
    pub storage_path: PathBuf,
}

impl AppState {
    pub fn new(storage: StorageFormat, storage_path: PathBuf) -> Self {
        AppState {
            storage,
            storage_path,
        }
    }
}

