use crate::errors::{AppError, AppResult};
use crate::models::StorageFormat;
use std::fs;
use std::path::{Path, PathBuf};

/// 初始化存储目录
pub fn init_storage(app_handle: &tauri::AppHandle) -> AppResult<PathBuf> {
    let app_data_dir = app_handle
        .path_resolver()
        .app_data_dir()
        .ok_or_else(|| AppError::StorageError("无法获取应用数据目录".to_string()))?;

    // 创建目录
    fs::create_dir_all(&app_data_dir)?;

    // 返回存储文件路径
    Ok(app_data_dir.join("lists.json"))
}

/// 从文件加载数据
pub fn load_data(path: &Path) -> AppResult<StorageFormat> {
    // 如果文件不存在，返回新的空数据
    if !path.exists() {
        return Ok(StorageFormat::new());
    }

    // 读取文件内容
    let content = fs::read_to_string(path)
        .map_err(|e| AppError::StorageError(format!("读取文件失败: {}", e)))?;

    // 解析 JSON
    let data: StorageFormat = serde_json::from_str(&content).map_err(|e| {
        // 如果解析失败，备份损坏的文件
        let backup_path = get_backup_path(path);
        let _ = fs::rename(path, &backup_path);
        eprintln!("数据文件损坏，已备份到: {}", backup_path.display());

        AppError::StorageError(format!("数据文件损坏，已备份。使用新的空数据。错误: {}", e))
    })?;

    // 验证数据版本
    if data.version != 1 {
        return Err(AppError::StorageError(format!(
            "不支持的数据格式版本: {}",
            data.version
        )));
    }

    Ok(data)
}

/// 保存数据到文件（原子写入）
pub fn save_data(path: &Path, data: &StorageFormat) -> AppResult<()> {
    // 序列化为 JSON
    let json = serde_json::to_string_pretty(data)?;

    // 写入临时文件
    let temp_path = path.with_extension("tmp");
    fs::write(&temp_path, json)
        .map_err(|e| AppError::StorageError(format!("写入临时文件失败: {}", e)))?;

    // 原子性地重命名文件（确保数据完整性）
    fs::rename(&temp_path, path)
        .map_err(|e| AppError::StorageError(format!("保存文件失败: {}", e)))?;

    Ok(())
}

/// 获取备份文件路径
fn get_backup_path(path: &Path) -> PathBuf {
    let timestamp = chrono::Utc::now().timestamp();
    path.with_extension(format!("backup.{}.json", timestamp))
}

/// 验证存储格式
pub fn validate_storage_format(data: &StorageFormat) -> AppResult<()> {
    // 检查版本
    if data.version != 1 {
        return Err(AppError::ValidationError(format!(
            "不支持的版本: {}",
            data.version
        )));
    }

    // 检查列表数量
    if data.lists.len() > 50 {
        return Err(AppError::ValidationError(
            "列表数量超过限制(50个)".to_string(),
        ));
    }

    // 检查列表名称唯一性
    let mut names = std::collections::HashSet::new();
    for list in &data.lists {
        if !names.insert(&list.name) {
            return Err(AppError::ValidationError(format!(
                "列表名称重复: {}",
                list.name
            )));
        }
    }

    // 检查每个列表的基金代码
    for list in &data.lists {
        if list.fund_codes.len() > 200 {
            return Err(AppError::ValidationError(format!(
                "列表 '{}' 的基金数量超过限制(200个)",
                list.name
            )));
        }

        // 检查列表内基金代码唯一性
        let mut codes = std::collections::HashSet::new();
        for code in &list.fund_codes {
            if !codes.insert(code) {
                return Err(AppError::ValidationError(format!(
                    "列表 '{}' 中基金代码重复: {}",
                    list.name, code
                )));
            }
        }
    }

    Ok(())
}

