            .unwrap()
            .filter_map(|e| e.ok())
            .filter(|e| {
                e.file_name()
                    .to_str()
                    .unwrap()
                    .starts_with("corrupted.backup")
            })
            .collect();
        assert!(!backup_files.is_empty());
    }
}

