    fn test_atomic_write() {
        let temp_dir = TempDir::new().unwrap();
        let path = temp_dir.path().join("test.json");

        let mut data = UserData::new();
        save_data(&path, &data).unwrap();

        // 再次保存
        data.touch();
        save_data(&path, &data).unwrap();

        // 确保临时文件被清理
        let temp_path = path.with_extension("tmp");
        assert!(!temp_path.exists());
    }

