import React, { useEffect, useState } from "react";
import { FundInfo } from "../types";
import { useTauriCommands } from "../hooks/useTauriCommands";

interface ListDetailProps {
  listId: string | null;
  listName: string;
  onListsChange: () => void;
  showToast?: (message: string, type: "success" | "error") => void;
  refreshMinutes?: number;
}

export const ListDetail: React.FC<ListDetailProps> = ({
  listId,
  listName,
  onListsChange,
  showToast,
  refreshMinutes,
}) => {
  const [funds, setFunds] = useState<FundInfo[]>([]);
  const [loading, setLoading] = useState(false);
  const [lastRefresh, setLastRefresh] = useState<Date | null>(null);
  const [newFundCode, setNewFundCode] = useState("");
  const { getListFunds, addFundToList, removeFundFromList } = useTauriCommands();

  const refreshInterval = Math.min(Math.max(refreshMinutes ?? 3, 1), 5);

  const loadFunds = async (silent = false) => {
    if (!listId) return;

    if (!silent) {
      setLoading(true);
    }
    try {
      const fundList = await getListFunds(listId);
      const uniqueFunds = new Map<string, FundInfo>();
      for (const fund of fundList) {
        if (!uniqueFunds.has(fund.code)) {
          uniqueFunds.set(fund.code, fund);
        }
      }
      if (uniqueFunds.size !== fundList.length && !silent) {
        showToast?.("已自动过滤重复基金数据", "error");
      }
      setFunds(Array.from(uniqueFunds.values()));
      setLastRefresh(new Date());
    } catch (error) {
      if (!silent && showToast) {
        showToast(String(error), "error");
      }
    } finally {
      if (!silent) {
        setLoading(false);
      }
    }
  };

  useEffect(() => {
    if (!listId) {
      setFunds([]);
      setLastRefresh(null);
      return;
    }

    loadFunds(false);
    const timer = setInterval(() => {
      loadFunds(true);
    }, refreshInterval * 60 * 1000);

    return () => clearInterval(timer);
  }, [listId, refreshInterval]);

  const handleRemove = async (fundCode: string) => {
    if (!listId) return;

    if (!confirm(`确定从列表中移除基金 ${fundCode} 吗？`)) {
      return;
    }

    try {
      await removeFundFromList(listId, fundCode);
      showToast?.("已从列表中移除", "success");
      loadFunds(false);
      onListsChange();
    } catch (error) {
      showToast?.(String(error), "error");
    }
  };

  const handleAddFund = async () => {
    if (!listId) return;
    const code = newFundCode.trim();
    if (!/^[0-9]{6}$/.test(code)) {
      showToast?.("请输入6位基金代码", "error");
      return;
    }

    try {
      await addFundToList(listId, code);
      showToast?.("已添加到列表", "success");
      setNewFundCode("");
      loadFunds(false);
      onListsChange();
    } catch (error) {
      showToast?.(String(error), "error");
    }
  };

  if (!listId) {
    return (
      <div className="list-detail-view empty">
        <p>👈 请选择一个列表查看详情</p>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="list-detail-view loading">
        <p>加载中...</p>
      </div>
    );
  }

  if (funds.length === 0) {
    return (
      <div className="list-detail-view empty">
        <h3>{listName}</h3>
        <p>列表为空，添加一些基金吧</p>
      </div>
    );
  }

  return (
    <div className="list-detail-view">
      <div className="detail-header">
        <div>
          <h3>{listName}</h3>
          {lastRefresh && (
            <div className="last-refresh">
              最近刷新：{lastRefresh.toLocaleTimeString()}
            </div>
          )}
        </div>
        <span className="fund-count">{funds.length}只基金</span>
      </div>

      <div className="list-add-fund">
        <input
          type="text"
          value={newFundCode}
          onChange={(e) =>
            setNewFundCode(e.target.value.replace(/\D/g, "").slice(0, 6))
          }
          placeholder="输入基金代码添加"
          maxLength={6}
          className="list-add-input"
        />
        <button onClick={handleAddFund} className="btn-add-inline">
          添加
        </button>
      </div>

      <div className="funds-grid">
        {funds.map((fund) => (
          <div key={fund.code} className="fund-card">
            <div className="fund-card-header">
              <span className="fund-code">{fund.code}</span>
              <button
                onClick={() => handleRemove(fund.code)}
                className="btn-remove"
                title="移除"
              >
                ✕
              </button>
            </div>
            <h4 className="fund-name">{fund.name}</h4>
            {fund.net_value !== null && (
              <div className="fund-value">
                净值: {fund.net_value.toFixed(4)}
              </div>
            )}
            {fund.change_percent && (
              <div className="fund-change">涨跌幅: {fund.change_percent}%</div>
            )}
            {fund.update_time && (
              <div className="fund-time">{fund.update_time}</div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

